    openingHours: {"Monday":"08:00–23:00","Tuesday":"08:00–23:00","Wednesday":"08:00–23:00","Thursday":"08:00–23:00","Friday":"08:00–00:00","Saturday":"08:00–00:00","Sunday":"08:00–23:00"},
